class Solution(object):
    def concatHex36(self, n):
        def to_base(num, base):
            if num == 0:
                return "0"
            chars = "0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ"
            res = []
            while num:
                res.append(chars[num % base])
                num //= base
            return "".join(reversed(res))
        return to_base(n * n, 16) + to_base(n * n * n, 36)
